import React, { useEffect, useState } from "react";
import { supabase } from "../supabaseClient";
import { 
    LogOut, RefreshCcw, MapPin, Clock, Phone, 
    Smartphone, CheckCircle, XCircle, Send, 
    Calendar, Loader2, ShieldCheck, MessageSquare
} from "lucide-react";
import "./Dashboard.css";

const Dashboard = ({ session }) => {
    const [rides, setRides] = useState([]);
    const [loading, setLoading] = useState(true);
    const [filter, setFilter] = useState("all");

    useEffect(() => {
        fetchRides();
        const sub = supabase.channel('pahel-hq').on('postgres_changes', { event: '*', schema: 'public', table: 'rides' }, () => fetchRides()).subscribe();
        return () => supabase.removeChannel(sub);
    }, []);

    const fetchRides = async () => {
        const { data } = await supabase.from("rides").select("*").order("created_at", { ascending: false });
        if (data) setRides(data);
        setLoading(false);
    };

    const updateStatus = async (id, status) => {
        await supabase.from('rides').update({ status }).eq('id', id);
        fetchRides();
    };

    const openWhatsApp = (number, name) => {
        const cleanNumber = number.replace(/\D/g, ''); // Sirf digits rakhega
        const message = `Hi ${name}, your PAHEL ride has been confirmed.`;
        window.open(`https://wa.me/91${cleanNumber}?text=${encodeURIComponent(message)}`, '_blank');
    };

    const stats = {
        total: rides.length,
        pending: rides.filter(r => r.status === 'pending').length,
        today: rides.filter(r => r.ride_date === new Date().toISOString().split('T')[0]).length,
        completed: rides.filter(r => r.status === 'completed').length
    };

    const filtered = filter === "all" ? rides : rides.filter(r => r.status === filter);

    if (loading) return (
        <div className="loader-container" style={{display:'flex', height:'100vh', alignItems:'center', justifyContent:'center'}}>
            <Loader2 className="spin" size={40} />
        </div>
    );

    return (
        <div className="dashboard-wrapper">
            <nav className="top-nav">
                <div className="logo-section">
                    <h1><ShieldCheck /> PAHEL OPS CENTER</h1>
                </div>
                <div style={{display:'flex', alignItems:'center', gap:'20px'}}>
                    <span style={{fontSize:'13px', opacity:0.8}}>{session.user.email}</span>
                    <button onClick={() => supabase.auth.signOut()} className="logout-link" style={{background:'none', border:'none', color:'#ff4d4d', cursor:'pointer', fontWeight:600}}>
                        LOGOUT
                    </button>
                </div>
            </nav>

            <div className="stats-container">
                <div className="stat-box"><span className="stat-label">Total Volume</span><span className="stat-value">{stats.total}</span></div>
                <div className="stat-box" style={{borderColor:'var(--warning)'}}><span className="stat-label">Pending Approval</span><span className="stat-value">{stats.pending}</span></div>
                <div className="stat-box" style={{borderColor:'var(--accent-blue)'}}><span className="stat-label">Today's Dispatch</span><span className="stat-value">{stats.today}</span></div>
                <div className="stat-box" style={{borderColor:'var(--success)'}}><span className="stat-label">Successful Rides</span><span className="stat-value">{stats.completed}</span></div>
            </div>

            <div className="main-content">
                <div className="table-card">
                    <div className="table-header-tools">
                        <div style={{display:'flex', gap:'10px'}}>
                            {['all', 'pending', 'confirmed', 'completed'].map(m => (
                                <button key={m} onClick={() => setFilter(m)} style={{
                                    padding:'6px 16px', borderRadius:'6px', border:'none',
                                    background: filter === m ? 'var(--sidebar-bg)' : '#e2e8f0',
                                    color: filter === m ? 'white' : 'var(--text-secondary)',
                                    cursor:'pointer', fontWeight:600, fontSize:'12px', textTransform:'uppercase'
                                }}>{m}</button>
                            ))}
                        </div>
                        <button onClick={fetchRides} className="action-btn"><RefreshCcw size={18} /></button>
                    </div>

                    <table className="data-table">
                        <thead>
                            <tr>
                                <th>Passenger</th>
                                <th>Contact (Click for WhatsApp)</th>
                                <th>Route</th>
                                <th>Schedule</th>
                                <th>Status</th>
                                <th>Control</th>
                            </tr>
                        </thead>
                        <tbody>
                            {filtered.map(ride => (
                                <tr key={ride.id}>
                                    <td data-label="Passenger"><strong>{ride.passenger_name}</strong></td>
                                    <td data-label="Contact">
                                        <button onClick={() => openWhatsApp(ride.phone_number, ride.passenger_name)} className="contact-link" style={{background:'none', border:'none', cursor:'pointer'}}>
                                            <MessageSquare size={14} /> {ride.phone_number}
                                        </button>
                                        {ride.alt_phone && <div style={{fontSize:'11px', color:'gray', marginLeft:'20px'}}>{ride.alt_phone}</div>}
                                    </td>
                                    <td data-label="Route">
                                        <div style={{fontSize:'12px'}}><MapPin size={10} color="green"/> {ride.pickup_location}</div>
                                        <div style={{fontSize:'12px'}}><MapPin size={10} color="red"/> {ride.drop_location}</div>
                                    </td>
                                    <td data-label="Schedule">
                                        <div style={{fontSize:'12px', fontWeight:600}}><Calendar size={12}/> {ride.ride_date}</div>
                                        <div style={{fontSize:'12px'}}><Clock size={12}/> {ride.ride_time}</div>
                                    </td>
                                    <td data-label="Status">
                                        <span style={{
                                            fontSize:'10px', fontWeight:700, padding:'4px 8px', borderRadius:'4px',
                                            background: ride.status === 'pending' ? '#fff7ed' : '#f0fdf4',
                                            color: ride.status === 'pending' ? '#c2410c' : '#15803d',
                                            border: `1px solid ${ride.status === 'pending' ? '#fdba74' : '#86efac'}`
                                        }}>{ride.status.toUpperCase()}</span>
                                    </td>
                                    <td data-label="Control">
                                        <div className="btn-group">
                                            <button onClick={() => updateStatus(ride.id, 'confirmed')} className="action-btn" title="Confirm"><Send size={14} color="blue"/></button>
                                            <button onClick={() => updateStatus(ride.id, 'completed')} className="action-btn" title="Complete"><CheckCircle size={14} color="green"/></button>
                                            <button onClick={() => updateStatus(ride.id, 'cancelled')} className="action-btn" title="Cancel"><XCircle size={14} color="red"/></button>
                                        </div>
                                    </td>
                                </tr>
                            ))}
                        </tbody>
                    </table>
                </div>
            </div>
        </div>
    );
};

export default Dashboard;
